DROP TABLE IF EXISTS `PEDIDO`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `PEDIDO` (
  `id_pedido` int NOT NULL,
  `Cantidad` int DEFAULT NULL,
  `total` decimal(10,2) DEFAULT NULL,
  `EMPLEADOS_nombre` varchar(90) NOT NULL,
  `EMPLEADOS_dni` char(9) NOT NULL,
  `num_mesa` int NOT NULL,
  PRIMARY KEY (`id_pedido`),
  KEY `fk_PEDIDO_EMPLEADOS1_idx` (`EMPLEADOS_nombre`,`EMPLEADOS_dni`),
  KEY `fk_PEDIDO_MESA1_idx` (`num_mesa`),
  CONSTRAINT `fk_PEDIDO_EMPLEADOS1` FOREIGN KEY (`EMPLEADOS_nombre`, `EMPLEADOS_dni`) REFERENCES `EMPLEADOS` (`nombre`, `dni`),
  CONSTRAINT `fk_PEDIDO_MESA1` FOREIGN KEY (`num_mesa`) REFERENCES `MESA` (`num_mesa`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

